set-variable.value:
@{
            var raw = context.Request.Url.QueryString ?? "";
            if (raw.StartsWith("?")) { raw = raw.Substring(1); }
            var kept = new System.Collections.Generic.List<string>();
            foreach (var pair in raw.Split('&'))
            {
                if (string.IsNullOrEmpty(pair)) { continue; }
                var eq = pair.IndexOf('=');
                var key = eq >= 0 ? pair.Substring(0, eq) : pair;
                if (key.Equals("resource", System.StringComparison.OrdinalIgnoreCase)) { continue; }
                if (key.Equals("scope", System.StringComparison.OrdinalIgnoreCase)) { continue; }
                kept.Add(pair);
            }
            kept.Add("scope=" + System.Net.WebUtility.UrlEncode("https://api.fabric.microsoft.com/.default offline_access openid profile"));
            return "https://login.microsoftonline.com/d7d6e19e-5176-4dea-a576-1681f77e0243/oauth2/v2.0/authorize?" + string.Join("&", kept);
        }
